mapper.select:
SELECT
aa.id, aa.venue_id, aa.schedule_id, aa.user_id, aa.user_name, aa.dept_id,
aa.person_count, aa.status, aa.appointment_date, aa.time_slot, aa.phone,
aa.remark, aa.approve_by, aa.approve_time, aa.approve_remark,
aa.enabled, aa.create_time, aa.update_time
FROM act_appointment aa
INNER JOIN act_venue v ON aa.venue_id = v.id
INNER JOIN act_schedule sch ON aa.schedule_id = sch.id
WHERE aa.enabled = '1' AND v.enabled = '1' AND sch.enabled = '1'

    AND aa.venue_id = #{req.venueId}


    AND aa.schedule_id = #{req.scheduleId}


    AND aa.user_id = #{req.userId}


    AND aa.user_name LIKE CONCAT('%', #{req.userName}, '%')


    AND aa.status = #{req.status}


    AND aa.appointment_date = #{req.appointmentDate}


    AND aa.phone = #{req.phone}


    ${req.dataScopeSql}

ORDER BY aa.create_time DESC, aa.id DESC
